// Utility to extract and send game data to Captivate from ProducerDashboard
import { sendToCaptivate } from '../utils/captivate';

export function sendRoundDataToCaptivate(roundData, player1, player2) {
  // Build the data object for Captivate
  const data = {
    // Player 1
    P1_Name: player1?.name,
    P1_Handle: player1?.handle,
    P1_Avatar: player1?.avatar,
    P1_Aura: player1?.aura,
    P1_Skill: player1?.skill,
    P1_Stamina: player1?.stamina,
    // Player 2
    P2_Name: player2?.name,
    P2_Handle: player2?.handle,
    P2_Avatar: player2?.avatar,
    P2_Aura: player2?.aura,
    P2_Skill: player2?.skill,
    P2_Stamina: player2?.stamina,
    // Card 1 (P1)
    C1: { ...roundData.C1 },
    // Card 2 (P2)
    C2: { ...roundData.C2 },
    // Winner card
    W: { ...roundData.W },
  };
  sendToCaptivate(data);
}
